namespace sv_55ce2899df1242199924d20c2ecf2692.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_55ce2899df1242199924d20c2ecf2692.Components.Pages.Settings

<nav class="settings-sidebar">
    <ul>
        @foreach (var section in Sections)
        {
            <li class="@(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionSelected.InvokeAsync(section)">
                <span class="sidebar-icon">@GetIcon(section)</span>
                <span class="sidebar-label">@section</span>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionSelected { get; set; }

    private static readonly string[] Sections = { "Profile", "Notifications", "Security", "Appearance" };

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-sidebar {
    width: 220px;
    border-right: 1px solid #e0e0e0;
    padding: 1rem 0;
}

.settings-sidebar ul {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-sidebar li {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    cursor: pointer;
    border-radius: 0 8px 8px 0;
    margin-right: 0.5rem;
    transition: background-color 0.2s, color 0.2s;
    font-weight: 500;
    color: #555;
}

.settings-sidebar li:hover {
    background-color: #f0f0f0;
    color: #333;
}

.settings-sidebar li.active {
    background-color: #e3f2fd;
    color: #1565c0;
    border-left: 3px solid #1565c0;
}

.sidebar-icon {
    font-size: 1.2rem;
}

