namespace sv_55ce2899df1242199924d20c2ecf2692.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_55ce2899df1242199924d20c2ecf2692.Components.Pages.Settings
@using sv_55ce2899df1242199924d20c2ecf2692.Services

@inject ISettingsService SettingsService

<section class="settings-section">
    <h2>Profile</h2>

    @if (_loading)
    {
        <p class="loading">Loading profile...</p>
    }
    else
    {
        <div class="profile-form">
            <div class="avatar-area">
                <div class="avatar-preview">
                    @if (!string.IsNullOrEmpty(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">👤</div>
                    }
                </div>
                <label>Avatar URL</label>
                <input type="url" @bind="_avatarUrl" @bind:event="oninput" />
            </div>

            <div class="form-group">
                <label>Display Name</label>
                <input type="text" @bind="_displayName" @bind:event="oninput" />
            </div>

            <div class="form-group">
                <label>Email</label>
                <input type="email" @bind="_email" @bind:event="oninput" />
            </div>

            <div class="form-group">
                <label>Bio</label>
                <textarea rows="4" @bind="_bio" @bind:event="oninput"></textarea>
            </div>

            <div class="form-actions">
                <button class="btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving..." : "Save Changes")
                </button>
                <button class="btn-secondary" @onclick="Discard" disabled="@_saving">
                    Discard Changes
                </button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast success">Profile saved successfully!</div>
            }
            @if (_errorMessage is not null)
            {
                <div class="toast error">@_errorMessage</div>
            }
        </div>
    }
</section>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;
    private string? _errorMessage;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        _loading = true;
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;
        _errorMessage = null;

        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _showSuccess = true;
            _ = HideSuccessAfterDelay();
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _errorMessage = null;
        _showSuccess = false;
    }
}

.settings-section h2 {
    margin-top: 0;
    margin-bottom: 1.5rem;
    font-size: 1.5rem;
    color: #333;
}

.loading {
    color: #888;
    font-style: italic;
}

.profile-form {
    max-width: 600px;
}

.avatar-area {
    margin-bottom: 1.5rem;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    overflow: hidden;
    border: 2px solid #e0e0e0;
    margin-bottom: 0.5rem;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f5f5f5;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 2rem;
}

.form-group {
    margin-bottom: 1.25rem;
}

.form-group label,
.avatar-area label {
    display: block;
    font-weight: 600;
    margin-bottom: 0.35rem;
    color: #444;
}

.form-group input,
.form-group textarea,
.avatar-area input {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 6px;
    font-size: 0.95rem;
    box-sizing: border-box;
}

.form-group textarea {
    resize: vertical;
}

.form-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

.btn-primary {
    background-color: #1565c0;
    color: #fff;
    border: none;
    padding: 0.6rem 1.25rem;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 600;
}

.btn-primary:hover:not(:disabled) {
    background-color: #0d47a1;
}

.btn-primary:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-secondary {
    background-color: #f5f5f5;
    color: #333;
    border: 1px solid #ccc;
    padding: 0.6rem 1.25rem;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 600;
}

.btn-secondary:hover:not(:disabled) {
    background-color: #e0e0e0;
}

.toast {
    margin-top: 1rem;
    padding: 0.75rem 1rem;
    border-radius: 6px;
    font-weight: 500;
}

.toast.success {
    background-color: #e8f5e9;
    color: #2e7d32;
    border: 1px solid #a5d6a7;
}

.toast.error {
    background-color: #ffebee;
    color: #c62828;
    border: 1px solid #ef9a9a;
}

