@namespace sv_55ce2899df1242199924d20c2ecf2692.Components.Pages.Settings
@using sv_55ce2899df1242199924d20c2ecf2692.Services

@inject ISettingsService SettingsService

<section class="settings-section">
    <h2>Profile</h2>

    @if (_loading)
    {
        <p class="loading">Loading profile...</p>
    }
    else
    {
        <div class="profile-form">
            <div class="avatar-area">
                <div class="avatar-preview">
                    @if (!string.IsNullOrEmpty(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">👤</div>
                    }
                </div>
                <label>Avatar URL</label>
                <input type="url" @bind="_avatarUrl" @bind:event="oninput" />
            </div>

            <div class="form-group">
                <label>Display Name</label>
                <input type="text" @bind="_displayName" @bind:event="oninput" />
            </div>

            <div class="form-group">
                <label>Email</label>
                <input type="email" @bind="_email" @bind:event="oninput" />
            </div>

            <div class="form-group">
                <label>Bio</label>
                <textarea rows="4" @bind="_bio" @bind:event="oninput"></textarea>
            </div>

            <div class="form-actions">
                <button class="btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving..." : "Save Changes")
                </button>
                <button class="btn-secondary" @onclick="Discard" disabled="@_saving">
                    Discard Changes
                </button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast success">Profile saved successfully!</div>
            }
            @if (_errorMessage is not null)
            {
                <div class="toast error">@_errorMessage</div>
            }
        </div>
    }
</section>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;
    private string? _errorMessage;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        _loading = true;
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;
        _errorMessage = null;

        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _showSuccess = true;
            _ = HideSuccessAfterDelay();
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _errorMessage = null;
        _showSuccess = false;
    }
}

