toolArgs.file_text:
.settings-section h2 {
    margin-top: 0;
    margin-bottom: 1.5rem;
    font-size: 1.5rem;
    color: #333;
}

.loading {
    color: #888;
    font-style: italic;
}

.profile-form {
    max-width: 600px;
}

.avatar-area {
    margin-bottom: 1.5rem;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    overflow: hidden;
    border: 2px solid #e0e0e0;
    margin-bottom: 0.5rem;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f5f5f5;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 2rem;
}

.form-group {
    margin-bottom: 1.25rem;
}

.form-group label,
.avatar-area label {
    display: block;
    font-weight: 600;
    margin-bottom: 0.35rem;
    color: #444;
}

.form-group input,
.form-group textarea,
.avatar-area input {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 6px;
    font-size: 0.95rem;
    box-sizing: border-box;
}

.form-group textarea {
    resize: vertical;
}

.form-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

.btn-primary {
    background-color: #1565c0;
    color: #fff;
    border: none;
    padding: 0.6rem 1.25rem;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 600;
}

.btn-primary:hover:not(:disabled) {
    background-color: #0d47a1;
}

.btn-primary:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-secondary {
    background-color: #f5f5f5;
    color: #333;
    border: 1px solid #ccc;
    padding: 0.6rem 1.25rem;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 600;
}

.btn-secondary:hover:not(:disabled) {
    background-color: #e0e0e0;
}

.toast {
    margin-top: 1rem;
    padding: 0.75rem 1rem;
    border-radius: 6px;
    font-weight: 500;
}

.toast.success {
    background-color: #e8f5e9;
    color: #2e7d32;
    border: 1px solid #a5d6a7;
}

.toast.error {
    background-color: #ffebee;
    color: #c62828;
    border: 1px solid #ef9a9a;
}

