{"file_text": "@namespace sv_55ce2899df1242199924d20c2ecf2692.Components.Pages.Settings
@using sv_55ce2899df1242199924d20c2ecf2692.Services

@inject ISettingsService SettingsService

<section class="settings-section">
    <h2>Security</h2>

    @if (_loading)
    {
        <p class="loading">Loading security settings...</p>
    }
    else
    {
        <div class="security-form">
            <!-- Change Password Panel -->
            <div class="expandable-panel">
                <button class="panel-header" @onclick="() => _passwordExpanded = !_passwordExpanded">
                    <span>Change Password</span>
                    <span class="expand-icon">@(_passwordExpanded ? "▼" : "▶")</span>
                </button>

                @if (_passwordExpanded)
                {
                    <div class="panel-body">
                        <div class="form-group">
                            <label>Current Password</label>
                            <input type="password" @bind="_currentPassword" />
                        </div>
                        <div class="form-group">
                            <label>New Password</label>
                            <input type="password" @bind="_newPassword" />
                        </div>
                        <div class="form-group">
                            <label>Confirm New Password</label>
                            <input type="password" @bind="_confirmPassword" />
                        </div>

                        @if (_passwordError is not null)
                        {
                            <div class="toast error">@_passwordError</div>
                        }
                        @if (_passwordSuccess)
                        {
                            <div class="toast success">Password updated successfully!</div>
                        }

                        <button class="btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                            @(_changingPassword ? "Updating..." : "Update Password")
                        </button>
                    </div>
                }
            </div>

            <!-- Two-Factor Authentication -->
            <div class="twofa-section">
                <h3>Two-Factor Authentication</h3>
                <div class="twofa-row">
                    <div class="twofa-status">
                        <span class="status-indicator @(_twoFactorEnabled ? "enabled" : "disabled")"></span>
                        <span>@(_twoFactorEnabled ? "Enabled" : "Disabled")</span>
                    </div>
                    <label class="toggle-row">
                        <input type="checkbox" @bind="_twoFactorEnabled" />
                    </label>
                </div>
                @if (_lastPasswordChange.HasValue)
                {
                    <p class="meta-text">Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
                }
            </div>

            <!-- Active Sessions -->
            <div class="sessions-section">
                <h3>Active Sessions</h3>
                @if (_sessions.Count == 0)
                {
                    <p class="empty-text">No active sessions.</p>
                }
                else
                {
                    <table class="sessions-table">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td>
                                        @if (session.Id != _currentSessionId)
                                        {
                                            <button class="btn-danger-sm" @onclick="() => ConfirmRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="current-badge">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                }
            </div>

            <!-- Revoke Confirmation Dialog -->
            @if (_sessionToRevoke is not null)
            {
                <div class="dialog-overlay" @onclick="CancelRevoke">
                    <div class="dialog" @onclick:stopPropagation="true">
                        <h4>Revoke Session</h4>
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                        <div class="dialog-actions">
                            <button class="btn-danger" @onclick="RevokeSessionAsync" disabled="@_revoking">
                                @(_revoking ? "Revoking..." : "Revoke")
                            </button>
                            <button class="btn-secondary" @onclick="CancelRevoke" disabled="@_revoking">
                                Cancel
                            </button>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
</section>

