.notifications-form {
    max-width: 600px;
}

.toggle-group {
    margin-bottom: 2rem;
}

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 0;
    border-bottom: 1px solid #f0f0f0;
    cursor: pointer;
}

.toggle-row span {
    font-weight: 500;
}

.toggle-row input[type="checkbox"] {
    width: 20px;
    height: 20px;
    accent-color: #1565c0;
}

.channels-section h3 {
    margin-bottom: 0.75rem;
    font-size: 1.1rem;
}

.channel-list {
    list-style: none;
    padding: 0;
    margin: 0;
}

.channel-row {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.5rem 0;
    cursor: pointer;
}

.channel-row input[type="checkbox"] {
    width: 18px;
    height: 18px;
    accent-color: #1565c0;
}

.empty-text {
    color: #888;
    font-style: italic;
}

