toolArgs.file_text:
.security-form {
    max-width: 700px;
}

.expandable-panel {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    margin-bottom: 1.5rem;
    overflow: hidden;
}

.panel-header {
    width: 100%;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 1rem 1.25rem;
    background: #fafafa;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    font-weight: 600;
    color: #333;
}

.panel-header:hover {
    background: #f0f0f0;
}

.expand-icon {
    font-size: 0.8rem;
    color: #888;
}

.panel-body {
    padding: 1.25rem;
    border-top: 1px solid #e0e0e0;
}

.panel-body .form-group {
    margin-bottom: 1rem;
}

.panel-body .form-group label {
    display: block;
    font-weight: 600;
    margin-bottom: 0.35rem;
    color: #444;
}

.panel-body .form-group input {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 6px;
    font-size: 0.95rem;
    box-sizing: border-box;
}

.twofa-section {
    margin-bottom: 2rem;
}

.twofa-section h3 {
    margin-bottom: 0.75rem;
}

.twofa-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.twofa-status {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.status-indicator {
    width: 12px;
    height: 12px;
    border-radius: 50%;
}

.status-indicator.enabled {
    background-color: #4caf50;
}

.status-indicator.disabled {
    background-color: #bdbdbd;
}

.meta-text {
    color: #888;
    font-size: 0.9rem;
    margin-top: 0.5rem;
}

.sessions-section h3 {
    margin-bottom: 0.75rem;
}

.sessions-table {
    width: 100%;
    border-collapse: collapse;
}

.sessions-table th,
.sessions-table td {
    padding: 0.75rem;
    text-align: left;
    border-bottom: 1px solid #e0e0e0;
}

.sessions-table th {
    font-weight: 600;
    color: #555;
    font-size: 0.9rem;
}

.btn-danger-sm {
    background-color: #e53935;
    color: white;
    border: none;
    padding: 0.35rem 0.75rem;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.85rem;
}

.btn-danger-sm:hover {
    background-color: #c62828;
}

.current-badge {
    font-size: 0.85rem;
    color: #1565c0;
    font-weight: 600;
}

.dialog-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

.dialog {
    background: white;
    padding: 2rem;
    border-radius: 12px;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
}

.dialog h4 {
    margin-top: 0;
    margin-bottom: 0.75rem;
}

.dialog-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

.btn-danger {
    background-color: #e53935;
    color: white;
    border: none;
    padding: 0.6rem 1.25rem;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 600;
}

.btn-danger:hover:not(:disabled) {
    background-color: #c62828;
}

.btn-danger:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

