                        <input type="radio" name="fontSize" value="Small" @onchange="() => _fontSize = &quot;Small&quot;" checked="@(_fontSize == "Small")" />
                        <span>Small</span>
                    </label>
                    <label class="radio-option">
                        <input type="radio" name="fontSize" value="Medium" @onchange="() => _fontSize = &quot;Medium&quot;" checked="@(_fontSize == "Medium")" />
                        <span>Medium</span>
                    </label>
                    <label class="radio-option">
                        <input type="radio" name="fontSize" value="Large" @onchange="() => _fontSize = &quot;Large&quot;" checked="@(_fontSize == "Large")" />
                        <span>Large</span>
                    </label>
                </div>
            </div>

            <!-- Language -->
            <div class="form-group">
                <label class="group-label">Language</label>
                <select @bind="_language">
                    <option value="en">English</option>
                    <option value="es">Español</option>
                    <option value="fr">Français</option>
                    <option value="de">Deutsch</option>
                    <option value="ja">日本語</option>
                    <option value="zh">中文</option>
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="form-group">
                <label class="toggle-row">
                    <span class="group-label">Compact Mode</span>
                    <input type="checkbox" @bind="_compactMode" />
                </label>
            </div>

            <!-- Live Preview -->
            <div class="preview-area @GetPreviewClasses()">
                <h4>Preview</h4>
                <p>This is how your content will look with the selected settings.</p>
                <div class="preview-card">
                    <strong>Sample Card</strong>
                    <p>Here is some sample text in your chosen font size and theme.</p>
                </div>
            </div>

            <div class="form-actions">
                <button class="btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving..." : "Save")
                </button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast success">Appearance settings saved!</div>
            }
        </div>
    }
</section>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var theme = _theme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            _ => "preview-light"
        };
        var size = _fontSize.ToLowerInvariant() switch
        {
            "small" => "preview-small",
            "large" => "preview-large",
            _ => "preview-medium"
        };
        var compact = _compactMode ? "preview-compact" : "";
        return $"{theme} {size} {compact}";
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;

        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);

        _saving = false;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

.appearance-form {
    max-width: 600px;
}

.group-label {
    font-weight: 600;
    color: #444;
    margin-bottom: 0.5rem;
    display: block;
}

.radio-group {
    display: flex;
    gap: 1.5rem;
    margin-top: 0.25rem;
}

.radio-option {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
    padding: 0.5rem 1rem;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    transition: border-color 0.2s;
}

.radio-option:has(input:checked) {
    border-color: #1565c0;
    background: #e3f2fd;
}

.radio-option input[type="radio"] {
    accent-color: #1565c0;
}

select {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 6px;
    font-size: 0.95rem;
    background: white;
}

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    cursor: pointer;
}

.toggle-row input[type="checkbox"] {
    width: 20px;
    height: 20px;
    accent-color: #1565c0;
}

/* Live Preview */
.preview-area {
    margin-top: 2rem;
    padding: 1.5rem;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    transition: all 0.3s;
}

.preview-area h4 {
    margin-top: 0;
    margin-bottom: 0.5rem;
}

.preview-card {
    margin-top: 1rem;
    padding: 1rem;
    border-radius: 6px;
    border: 1px solid #ddd;
}

/* Theme variants */
.preview-light {
    background-color: #ffffff;
    color: #333;
}

.preview-light .preview-card {
    background: #f9f9f9;
}

.preview-dark {
    background-color: #1e1e1e;
    color: #e0e0e0;
}

.preview-dark .preview-card {
    background: #2d2d2d;
    border-color: #444;
}

/* Font size variants */
.preview-small {
    font-size: 0.85rem;
}

.preview-medium {
    font-size: 1rem;
}

.preview-large {
    font-size: 1.15rem;
}

/* Compact variant */
.preview-compact {
    padding: 0.75rem;
    line-height: 1.3;
}

.preview-compact .preview-card {
    padding: 0.5rem;
    margin-top: 0.5rem;
}

